// ─────────────────────────────────────────────────────────────────────────
// Master dispatcher: validate_transition
//   w0 = current_state, w1 = next_state, x2 = prerequisites
//   Returns: 1 = valid, 0 = invalid
// ─────────────────────────────────────────────────────────────────────────
.globl validate_transition
.type  validate_transition, %function
validate_transition:
    // Bounds check: 0 <= current_state <= 7
    cmp  w0, #0
    b.lt .Linvalid_transition_main
    cmp  w0, #7
    b.gt .Linvalid_transition_main

    // Bounds check: 0 <= next_state <= 7
    cmp  w1, #0
    b.lt .Linvalid_transition_main
    cmp  w1, #7
    b.gt .Linvalid_transition_main

    // Reset: next_state == 0 is always valid
    cbz  w1, .Lvalid_transition_main

    // Sequential check: next_state must equal current_state + 1
    add  w3, w0, #1
    cmp  w1, w3
    b.ne .Linvalid_transition_main

    // Prerequisite bit check: bit (next_state - 1) must be set in x2
    sub  w4, w1, #1         // w4 = next_state - 1
    mov  x3, #1
    lsl  x3, x3, x4         // x3 = 1 << (next_state - 1)
    tst  x2, x3
    b.eq .Linvalid_transition_main

.Lvalid_transition_main:
    mov  w0, #1
    ret

.Linvalid_transition_main:
    mov  w0, #0
    ret

.size validate_transition, .-validate_transition

